#ifndef RTOS_TASK_H
#define RTOS_TASK_H
#include <Arduino.h>
#include <freertos/FreeRTOS.h>
#include <freertos/task.h>

typedef void (*TaskFunction)(void);

TaskHandle_t rtos_create_task(const char* name, TaskFunction fn, uint32_t stackSize = 4096, 
                              UBaseType_t priority = 5, BaseType_t core = 1);
void rtos_delete_task(TaskHandle_t handle);
UBaseType_t rtos_stack_watermark(TaskHandle_t handle);
void rtos_task_delay(uint32_t ms);

#endif

firmware_template.source:
#include "rtos_task.h"

struct TaskParams {
    TaskFunction fn;
    uint32_t intervalMs;
};

static void _taskWrapper(void* params) {
    TaskParams* tp = (TaskParams*)params;
    for (;;) {
        tp->fn();
        vTaskDelay(pdMS_TO_TICKS(tp->intervalMs));
    }
}

TaskHandle_t rtos_create_task(const char* name, TaskFunction fn, uint32_t stackSize, 
                              UBaseType_t priority, BaseType_t core) {
    TaskHandle_t handle = NULL;
    static TaskParams params; // static so it persists
    params.fn = fn;
    params.intervalMs = 100;

    BaseType_t result;
    if (core >= 0) {
        result = xTaskCreatePinnedToCore(_taskWrapper, name, stackSize, &params, priority, &handle, core);
    } else {
        result = xTaskCreate(_taskWrapper, name, stackSize, &params, priority, &handle);
    }

    if (result == pdPASS) {
        Serial.printf("[rtos] Task '%s' created (stack=%lu, pri=%d, core=%d)\n", name, stackSize, priority, core);
    } else {
        Serial.printf("[rtos] FAILED to create task '%s'\n", name);
    }
    return handle;
}

void rtos_delete_task(TaskHandle_t handle) {
    if (handle) vTaskDelete(handle);
}

UBaseType_t rtos_stack_watermark(TaskHandle_t handle) {
    return uxTaskGetStackHighWaterMark(handle);
}

void rtos_task_delay(uint32_t ms) {
    vTaskDelay(pdMS_TO_TICKS(ms));
}
